tinymce.PluginManager.add('imagetag', function(editor, url) {
    editor.ui.registry.addIcon('imagetag', '<?xml version="1.0" encoding="utf-8"?>\n' +
        '<!-- Generator: Adobe Illustrator 16.0.0, SVG Export Plug-In . SVG Version: 6.00 Build 0)  -->\n' +
        '<!DOCTYPE svg PUBLIC "-//W3C//DTD SVG 1.1//EN" "http://www.w3.org/Graphics/SVG/1.1/DTD/svg11.dtd">\n' +
        '<svg version="1.1" id="Layer_1" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" x="0px" y="0px"\n' +
        '\t width="19.01px" height="15.992px" viewBox="0 0 19.01 15.992" enable-background="new 0 0 19.01 15.992" xml:space="preserve">\n' +
        '<g>\n' +
        '\t<g>\n' +
        '\t\t<path fill-rule="evenodd" clip-rule="evenodd" d="M2,3.5C2,4.328,2.672,5,3.5,5S5,4.328,5,3.5S4.328,2,3.5,2S2,2.672,2,3.5z M1,1\n' +
        '\t\t\th11v5h1V0H0v12h8v-2H1V1z M8,3L6,8L5,6L2,9h6V6h1.5L8,3z M13.665,6.994L8.988,7.068l0.082,4.296l5.344,4.628l4.596-4.371\n' +
        '\t\t\tL13.665,6.994z M12.954,10.586c-0.424,0.402-1.121,0.414-1.56,0.025c-0.438-0.389-0.45-1.03-0.027-1.433\n' +
        '\t\t\tc0.424-0.402,1.121-0.413,1.56-0.024C13.364,9.543,13.377,10.184,12.954,10.586z"/>\n' +
        '\t</g>\n' +
        '</g>\n' +
        '</svg>');

    var openDialog = function () {
        var cid = editor.getParam('content_id');
        var ctype = editor.getParam('content_type');
        var module_code = editor.getParam('module_code');
        var query = '?cid='+cid+'&ctype='+ctype+'&moduleCode='+module_code;
        return editor.windowManager.openUrl({
            url: tinymce.baseURL + '/plugins/imagetag/scripts/image_tag.php'+query,
            title: 'Image Tag',
            width: 740,
            height: 390,
        });
    };

    editor.ui.registry.addButton('imagetag', {
        tooltip: 'Image Tag',
        icon: 'imagetag',
        onAction: function () {
            // Open window
            openDialog();
        }

    });

    // Adds a menu item, which can then be included in any menu via the menu/menubar configuration
    editor.ui.registry.addMenuItem('imagetag', {
        text: 'Image Tag',
        icon: 'imagetag',
        onAction: function () {
            // Open window
            openDialog();
        }
    });
});